diff --git a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
index ecbc13d489eb..1e4da337bfd8 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -3077,9 +3077,24 @@ bool VectorCombine::run() {
   if (DisableVectorCombine)
     return false;

-  // Don't attempt vectorization if the target does not support vectors.
-  if (!TTI.getNumberOfRegisters(TTI.getRegisterClassForType(/*Vector*/ true)))
-    return false;
+  if (auto *NewCmp = dyn_cast<ICmpInst>(NewBinOp)) {
+    ICmpInst *Cmp0 = cast<ICmpInst>(I0);
+    ICmpInst *Cmp1 = cast<ICmpInst>(I1);
+    ICmpInst::Predicate Pred0 = Cmp0->getPredicate();
+    ICmpInst::Predicate Pred1 = Cmp1->getPredicate();
+    ICmpInst::Predicate NewPred = Pred0;
+    if (Pred0 != Pred1) {
+      assert(Cmp0->hasNoSignedWrap() && Cmp1->hasNoSignedWrap() &&
+             "Cannot combine different predicates without samesign");
+      NewPred = ICmpInst::getSignedPredicate(Pred0);
+      assert(NewPred == ICmpInst::getSignedPredicate(Pred1) &&
+             "Signed predicates do not match");
+    }
+    NewCmp->setPredicate(NewPred);
+    if (Cmp0->hasNoSignedWrap() && Cmp1->hasNoSignedWrap())
+      NewCmp->setHasNoSignedWrap(true);
+  }
+

   LLVM_DEBUG(dbgs() << "\n\nVECTORCOMBINE on " << F.getName() << "\n");

